import requests

# RabbitMQ Management API endpoint
rabbitmq_url = "http://localhost:15672"
username = "admin"
password = "password"

# List of vhosts to create
vhosts = {
    "app1": {},
    "app2": {},
}

# Create virtual hosts
for vhost_name, vhost_config in vhosts.items():
    response = requests.put(
        f"{rabbitmq_url}/api/vhosts/{vhost_name}",
        auth=(username, password),
        json=vhost_config,
    )
    response.raise_for_status()

# Create users and grant permissions
users = {
    "user1": {"password": "password1"},
    "user2": {"password": "password2"},
}
permissions = {
    "app1": {"read": True, "write": True, "configure": True},
    "app2": {"read": True, "write": True, "configure": True},
}

for user_name, user_config in users.items():
    response = requests.put(
        f"{rabbitmq_url}/api/users/{user_name}",
        auth=(username, password),
        json=user_config,
    )
    response.raise_for_status()

for user_name, permissions in permissions.items():
    for vhost_name, permission in permissions.items():
        response = requests.put(
            f"{rabbitmq_url}/api/permissions/{vhost_name}/{user_name}",
            auth=(username, password),
            json=permission,
        )
        response.raise_for_status()